// get mcat_id from Seller Specs node
const mcat_id = $node["Seller Specs"].json.mcat_id || "";

// get AI response text
let aiText = items[0].json.output || items[0].json.text || "";

// remove markdown if present
aiText = aiText.replace(/```json/g, "").replace(/```/g, "").trim();

// parse JSON
const response = JSON.parse(aiText);

const rows = [];

// MISSING SPECS
(response.missing_specs || []).forEach(spec => {

  rows.push({
    json: {
      mcat_id: mcat_id,
      category: response.category_name || "",
      spec_name: spec.spec_name || "",
      options: (spec.options || []).join(", "),
      status: "missing",
      reason: spec.missing_reason || "",
      covered_by: ""
    }
  });

});

// NOT MISSING SPECS
// NOT MISSING SPECS
(response.not_missing_specs || []).forEach(spec => {

  rows.push({
    json: {
      mcat_id: mcat_id,
      category: response.category_name || "",
      spec_name: spec.spec_name || "",
      options: (spec.options || []).join(", "),
      status: "not_missing",
      reason: spec.reason || "",
      covered_by: spec.covered_by_platform_spec || ""
    }
  });

});

// ⭐ IMPORTANT: if no rows, send a dummy item so next nodes run
if (rows.length === 0) {
  rows.push({
    json: {
      mcat_id: mcat_id,
      category: response.category_name || "",
      spec_name: "",
      options: "",
      status: "no_missing_specs",
      reason: "",
      covered_by: ""
    }
  });
}

return rows;

// Run Once for All Items

return items.map((item) => {
  const data = item.json || {};

  const mcat_id =
    data.mcat_id ??
    data.mcatId ??
    null;

  // try direct known locations first
  let url =
    data?.finalized_specs?.file_info?.url ??
    data?.finalized_specs?.file_info?.file_path ?? // if you want to fallback to gs:// too
    data?.url ??
    null;

  // ultimate fallback: search entire object for any https://storage.googleapis.com/... occurrence
  if (!url) {
    const jsonStr = JSON.stringify(data);
    const m = jsonStr.match(/https:\/\/storage\.googleapis\.com\/[^\s"']+/);
    if (m) url = m[0];
  }

  return {
    json: {
      mcat_id,
      finalized_spec_url: url || null,
    },
  };
});

const specs = [];

const fs = items[0].json.finalized_specs;

fs.finalized_primary_specs.specs.forEach(s => {
  if (s.options) {
    specs.push({ spec_name: s.spec_name, spec_options: s.options.slice(0, 6) });
  }
});

fs.finalized_secondary_specs.specs.forEach(s => {
  if (s.options) {
    specs.push({ spec_name: s.spec_name, spec_options: s.options.slice(0, 6) });
  }
});

fs.finalized_tertiary_specs.specs.forEach(s => {
  if (s.options) {
    specs.push({ spec_name: s.spec_name, spec_options: s.options.slice(0, 6) });
  }
});

return [{
  json: {
    category: items[0].json.category_name,
    platform_specs: specs
  }
}];

const seller = $node["Final Seller Specs"].json.platform_specs;
const buyer = $node["Filtering"].json.buyer_specs;

return [{
  json: {
    category: $node["Final Seller Specs"].json.category,
    seller_specs: seller,
    buyer_specs: buyer
  }
}];

// get current MCAT from loop node
const currentMcat = String($node["Loop Over Items"].json.mcat_name || "")
  .toLowerCase()
  .trim();

// filter rows belonging to this MCAT
const filtered = items.filter(i => {
  const buyerMcat = String(i.json["mcat_name"] || "").toLowerCase().trim();
  return buyerMcat === currentMcat;
});

const grouped = {};

for (const item of filtered) {

  const spec = String(item.json["Spec Name"] || "").toLowerCase().trim();
  const option = String(item.json["Spec Option"] || "").trim();
  const impressions = Number(item.json["Impression"] || 0);

  if (!spec || !option) continue;

  if (!grouped[spec]) {
    grouped[spec] = {
      total_impressions: 0,
      options: []
    };
  }

  grouped[spec].total_impressions += impressions;

  grouped[spec].options.push({
    option,
    impressions
  });
}

const specs = [];

for (const spec in grouped) {

  // apply condition only on total impressions
  if (grouped[spec].total_impressions < 50) continue;

  const topOptions = grouped[spec].options
    .sort((a,b)=>b.impressions-a.impressions)
    .slice(0,10)
    .map(o => o.option);

  specs.push({
    spec_name: spec,
    total_impressions: grouped[spec].total_impressions,
    spec_options: topOptions
  });
}

// select top 10 specs by impressions
const topSpecs = specs
  .sort((a,b)=>b.total_impressions-a.total_impressions)
  .slice(0,10);

return [{
  json:{
    category: $node["Loop Over Items"].json.mcat_name,
    buyer_specs: topSpecs
  }
}];
